import{_ as p,o as r,c as o,ag as t}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"金鼓谣·第一季剧本","description":"","frontmatter":{"title":"金鼓谣·第一季剧本","outline":false},"headers":[],"relativePath":"novels/jin-gu-yao/drama/screenplay.md","filePath":"novels/jin-gu-yao/drama/screenplay.md","lastUpdated":null}'),a={name:"novels/jin-gu-yao/drama/screenplay.md"};function n(s,e,m,g,l,h){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="金鼓谣-·-第一季「长安」完整剧本" tabindex="-1">金鼓谣 · 第一季「长安」完整剧本 <a class="header-anchor" href="#金鼓谣-·-第一季「长安」完整剧本" aria-label="Permalink to &quot;金鼓谣 · 第一季「长安」完整剧本&quot;">​</a></h1><hr><h2 id="视频风格" tabindex="-1">视频风格 <a class="header-anchor" href="#视频风格" aria-label="Permalink to &quot;视频风格&quot;">​</a></h2><p><strong>画风</strong>：国风动漫 <strong>画面比例</strong>：9:16（竖屏短剧） <strong>美术方向</strong>：水墨淡彩 + 工笔人物，整体色调偏暖黄（宣纸色），夜戏转冷月蓝灰。建筑、服饰参考隋末唐初，兼顾动漫感的线条张力。 <strong>镜头语言</strong>：多用特写（眼神、手部动作）和大远景（城墙、月色、官道）形成反差。转场以水墨晕染过渡。 <strong>配乐基调</strong>：古琴 + 竹笛为主，紧张段落加鼓点，日常段落用轻快的琵琶拨弦。</p><hr><h2 id="剧本摘要" tabindex="-1">剧本摘要 <a class="header-anchor" href="#剧本摘要" aria-label="Permalink to &quot;剧本摘要&quot;">​</a></h2><h3 id="一句话故事" tabindex="-1">一句话故事 <a class="header-anchor" href="#一句话故事" aria-label="Permalink to &quot;一句话故事&quot;">​</a></h3><p>大业十三年，李渊第三女缝完丈夫最后一件袍子，决定自己去造反。</p><h3 id="故事类型" tabindex="-1">故事类型 <a class="header-anchor" href="#故事类型" aria-label="Permalink to &quot;故事类型&quot;">​</a></h3><p>历史传奇 / 女性崛起 / 权谋悬疑</p><h3 id="故事背景" tabindex="-1">故事背景 <a class="header-anchor" href="#故事背景" aria-label="Permalink to &quot;故事背景&quot;">​</a></h3><p>隋朝末年，大业十三年（公元 617 年）。天下大乱将至，各地义军蜂起。隋炀帝远在江都，长安城表面平静，暗流涌动。李渊在太原密谋起兵，密信传至长安。</p><h3 id="故事设定" tabindex="-1">故事设定 <a class="header-anchor" href="#故事设定" aria-label="Permalink to &quot;故事设定&quot;">​</a></h3><ul><li>短剧采用<strong>倒叙开场法</strong>——先给最炸的画面，再回头讲&quot;她怎么走到这一步&quot;</li><li>每集 3-5 分钟，每集结尾设置&quot;钩子&quot;悬念</li><li>不是&quot;加戏&quot;，而是&quot;重新剪辑&quot;——原小说素材换呈现顺序</li><li>第一季共 5 集，改编自小说序章 + 第一章</li></ul><h3 id="故事梗概" tabindex="-1">故事梗概 <a class="header-anchor" href="#故事梗概" aria-label="Permalink to &quot;故事梗概&quot;">​</a></h3><p>柴绍收到李渊密信，必须连夜奔赴太原。三娘独自留守长安，带着两个年幼的儿子和家仆马三宝。但她并非被动等待——八年前她已暗中调查鄠县地形、粮仓、人口。柴绍离开当晚，她换上男装，携子出城，踏上前往鄠县的路。与此同时，鄠县县令已经嗅到风声，布下暗棋。两个棋手，即将在同一个棋盘上相遇。</p><hr><h2 id="主角与主要人物" tabindex="-1">主角与主要人物 <a class="header-anchor" href="#主角与主要人物" aria-label="Permalink to &quot;主角与主要人物&quot;">​</a></h2><h3 id="三娘-李氏-·-平阳昭公主-——-主角" tabindex="-1">三娘（李氏 · 平阳昭公主）—— 主角 <a class="header-anchor" href="#三娘-李氏-·-平阳昭公主-——-主角" aria-label="Permalink to &quot;三娘（李氏 · 平阳昭公主）—— 主角&quot;">​</a></h3><ul><li><strong>身份</strong>：李渊第三女，柴绍之妻</li><li><strong>年龄</strong>：约二十五六岁</li><li><strong>视觉特点</strong>：清瘦高挑，面容端正但不施粉黛。眼神冷静锐利，嘴角常带一丝不易察觉的笑意。换男装后像个清秀少年，但举止间有种不属于少年的沉稳。</li><li><strong>服饰</strong>：日常穿素色窄袖襦裙，不戴繁复首饰；男装时着深色圆领袍、束发戴幞头</li><li><strong>核心气质</strong>：外冷内热，果断隐忍，像一把藏在绸缎下的刀</li></ul><h3 id="柴绍-——-三娘的丈夫" tabindex="-1">柴绍 —— 三娘的丈夫 <a class="header-anchor" href="#柴绍-——-三娘的丈夫" aria-label="Permalink to &quot;柴绍 —— 三娘的丈夫&quot;">​</a></h3><ul><li><strong>身份</strong>：隋朝右千牛备身（皇帝近卫武官）</li><li><strong>视觉特点</strong>：高大结实，国字脸，笑起来憨厚可靠。当值时英武严肃，回家秒变&quot;猎鹿不成猎兔子&quot;的大男孩。</li><li><strong>服饰</strong>：当值时穿官袍、佩横刀；猎装时粗犷利落</li><li><strong>核心气质</strong>：忠厚、勇武、有担当，但在三娘面前总差半拍</li></ul><h3 id="马三宝-——-家仆-三娘的左膀右臂" tabindex="-1">马三宝 —— 家仆 / 三娘的左膀右臂 <a class="header-anchor" href="#马三宝-——-家仆-三娘的左膀右臂" aria-label="Permalink to &quot;马三宝 —— 家仆 / 三娘的左膀右臂&quot;">​</a></h3><ul><li><strong>身份</strong>：柴府家仆，跟随三娘多年</li><li><strong>视觉特点</strong>：中等个头，瘦长脸，表情丰富。永远一副苦哈哈的操心样，但关键时刻挡在最前面。手工活糟糕（削的木马像老鼠）。</li><li><strong>服饰</strong>：灰褐色短打粗布衣，束腰利落</li><li><strong>核心气质</strong>：忠心耿耿，嘴碎但靠谱，天生的喜剧担当</li></ul><h3 id="柴哲威-——-长子" tabindex="-1">柴哲威 —— 长子 <a class="header-anchor" href="#柴哲威-——-长子" aria-label="Permalink to &quot;柴哲威 —— 长子&quot;">​</a></h3><ul><li><strong>年龄</strong>：五岁</li><li><strong>视觉特点</strong>：继承了柴绍的方脸，表情总是严肃得不像小孩。走路昂首挺胸，自封&quot;小将军&quot;。</li><li><strong>核心气质</strong>：早熟、倔强、有主见</li></ul><h3 id="柴令武-——-次子" tabindex="-1">柴令武 —— 次子 <a class="header-anchor" href="#柴令武-——-次子" aria-label="Permalink to &quot;柴令武 —— 次子&quot;">​</a></h3><ul><li><strong>年龄</strong>：三岁</li><li><strong>视觉特点</strong>：圆脸大眼，永远鼻涕泡一鼓一鼓。哭起来惊天动地，睡着了像个小天使（还流口水）。</li><li><strong>核心气质</strong>：幼稚可爱、爱撒娇、行走的气氛调节器</li></ul><h3 id="窦氏-——-三娘的母亲-回忆中" tabindex="-1">窦氏 —— 三娘的母亲（回忆中） <a class="header-anchor" href="#窦氏-——-三娘的母亲-回忆中" aria-label="Permalink to &quot;窦氏 —— 三娘的母亲（回忆中）&quot;">​</a></h3><ul><li><strong>视觉特点</strong>：眼角有细纹但眼睛极亮，&quot;像灯芯刚拨过&quot;。气度从容，说话不疾不徐但每句都有分量。</li><li><strong>服饰</strong>：贵族妇人装束，但不繁缛，干净利落</li><li><strong>核心气质</strong>：智慧、刚毅、温柔而锋利</li></ul><h3 id="鄠县县令-蔡知县-——-暗线反派" tabindex="-1">鄠县县令（蔡知县） —— 暗线反派 <a class="header-anchor" href="#鄠县县令-蔡知县-——-暗线反派" aria-label="Permalink to &quot;鄠县县令（蔡知县） —— 暗线反派&quot;">​</a></h3><ul><li><strong>视觉特点</strong>：中年，不胖不瘦，面相普通但眼睛很亮。坐着不动时像个无害的文官，开口说话才知道老辣。</li><li><strong>服饰</strong>：深色官服，不讲究但整洁</li><li><strong>核心气质</strong>：隐忍、多疑、棋手型人物——下手比谁都早</li></ul><hr><h2 id="第一季-·-长安-共-5-集" tabindex="-1">第一季 · 长安（共 5 集） <a class="header-anchor" href="#第一季-·-长安-共-5-集" aria-label="Permalink to &quot;第一季 · 长安（共 5 集）&quot;">​</a></h2><hr><h3 id="第-1-集-缝不完的袍子" tabindex="-1">第 1 集：缝不完的袍子 <a class="header-anchor" href="#第-1-集-缝不完的袍子" aria-label="Permalink to &quot;第 1 集：缝不完的袍子&quot;">​</a></h3><blockquote><p>钩子类型：悬念 + 身份反转 时长：约 3 分钟</p></blockquote><hr><h4 id="【开场-·-闪前】" tabindex="-1">【开场 · 闪前】 <a class="header-anchor" href="#【开场-·-闪前】" aria-label="Permalink to &quot;【开场 · 闪前】&quot;">​</a></h4><p><em>画面：夜色。一个穿男装的清瘦身影站在门口，背对镜头。远处是黑沉沉的长安城。</em></p><p><strong>三娘（画外音）</strong>：大业十三年，我缝完了丈夫最后一件袍子。然后决定去造反。</p><p><em>她转身。灯光照亮半张脸——冷静、笃定。</em></p><p><strong>三娘</strong>：三宝，明天起，叫我李公子。</p><p><em>【黑屏。打出字幕：三天前。】</em></p><hr><h4 id="【正片开始】" tabindex="-1">【正片开始】 <a class="header-anchor" href="#【正片开始】" aria-label="Permalink to &quot;【正片开始】&quot;">​</a></h4><p><strong>场景：柴府院子，傍晚</strong></p><p><em>三娘坐在廊下缝袍子。阳光懒洋洋的。</em></p><p><em>远处两个孩子在打架——</em></p><p><strong>柴令武</strong>（3岁，嚎叫）：娘——！哥哥又抢我的木马！</p><p><strong>柴哲威</strong>（5岁，面不改色）：我没抢。它自己断的。</p><p><strong>柴令武</strong>：你拽断的！</p><p><strong>柴哲威</strong>：它本来就要断了。</p><p><em>三娘头也不抬。</em></p><p><strong>三娘</strong>：哲威，把马还给弟弟。</p><p><em>柴哲威一脸不情愿地把半截木马塞给弟弟。柴令武接过去，看了看——愣了三秒，嚎啕大哭。</em></p><p><em>马三宝从厨房探出头来。</em></p><p><strong>马三宝</strong>：怎么了怎么了？</p><p><strong>三娘</strong>：木马断了。</p><p><strong>马三宝</strong>（精准判断）：大公子干的？</p><p><em>柴哲威踢蚂蚁的脚顿了一下。</em></p><p><strong>三娘</strong>：三宝，找块木头，给令武削一个新的。</p><p><strong>马三宝</strong>：夫人，上次那个您说像老鼠……</p><p><strong>三娘</strong>：那这次削好看点。</p><p><strong>马三宝</strong>（苦脸）：……我尽量。</p><p><em>厨房传来翻箱倒柜的声音，然后一声闷响。</em></p><p><strong>马三宝</strong>（画外）：哎哟——</p><p><em>三娘摇头，叹口气，低头继续缝袍子。</em></p><p><em>缝了两针，嘴角忍不住弯了一下。</em></p><p><strong>三娘（画外音）</strong>：这件袍子，去年秋天柴绍猎鹿时剐的。搁了大半年了，不是没时间缝——是每次拿起来就想到他。</p><hr><h4 id="【插入-快速闪回】" tabindex="-1">【插入：快速闪回】 <a class="header-anchor" href="#【插入-快速闪回】" aria-label="Permalink to &quot;【插入：快速闪回】&quot;">​</a></h4><p><em>画面闪过：柴绍满身是泥，兴高采烈把一只瘸腿兔子放到三娘面前。</em></p><p><strong>柴绍</strong>：三娘你看！</p><p><strong>三娘</strong>：你去猎鹿，猎回来一只兔子。兔子还是瘸的。</p><p><strong>柴绍</strong>（不以为意）：鹿跑了，但这兔子肥啊！</p><p><em>闪回结束。</em></p><hr><h4 id="【回到院子】" tabindex="-1">【回到院子】 <a class="header-anchor" href="#【回到院子】" aria-label="Permalink to &quot;【回到院子】&quot;">​</a></h4><p><em>院子里恢复了平静。小的趴在三娘腿上睡着了，鼻涕泡一鼓一鼓。大的在院子里用竹竿&quot;杀敌&quot;，把槐花打了一地。</em></p><p><em>门响。</em></p><p><em>三娘以为是马三宝，没抬头。</em></p><p><strong>柴绍</strong>（低声）：三娘。</p><p><em>三娘手指一顿。她抬起头——</em></p><p><em>柴绍站在门口，当值袍服，腰间横刀没解。脸上的表情她从没见过。</em></p><p><strong>三娘（画外音）</strong>：我见过他高兴的样子、心虚的样子、紧张的样子。但这一次——像一个人同时踩到了金子和蛇。</p><p><em>柴绍的目光扫过睡着的小儿子和挥竹竿的大儿子。</em></p><p><strong>柴绍</strong>：孩子们……</p><p><em>三娘秒懂。她轻轻放下小儿子，盖好薄衫。</em></p><p><strong>三娘</strong>：哲威，去找三宝。</p><p><strong>柴哲威</strong>：我不想去，三宝削的马好丑——</p><p><strong>三娘</strong>：柴哲威。</p><p><em>五岁的柴哲威精准识别出&quot;再说一个字试试&quot;的信号，竹竿一扔，跑了。</em></p><p><em>院子安静。槐花还在落。</em></p><p><em>柴绍从怀里掏出一截竹管。</em></p><p><em>三娘看到上面的刻字——</em></p><p><em>特写：一个&quot;渊&quot;字。</em></p><p><em>三娘接过来。手指碰到柴绍的手，感觉到——他在抖。</em></p><p><em>她挑开蜡封，抽出绢帛。</em></p><p><em>镜头不给绢帛内容，只拍三娘的眼睛——看了第一遍，平静；看了第二遍，瞳孔微缩。</em></p><p><em>她把绢帛折好。</em></p><p><strong>三娘</strong>（声音平稳）：父亲要起兵。他让你去太原。</p><p><em>长停顿。</em></p><p><em>远处柴哲威的声音飘过来：</em></p><p><strong>柴哲威</strong>（远处）：三宝——你在削什么？好丑啊！</p><p><strong>马三宝</strong>（远处）：你行你来！</p><p><em>柴绍深吸一口气。</em></p><p><strong>柴绍</strong>：三娘，我得走。可是——你们留在长安……万一隋兵来查……</p><p><em>三娘看着他。灯光里，柴绍的脸一半亮一半暗。</em></p><p><strong>三娘</strong>：你走吧。</p><p><em>柴绍愣住。</em></p><p><strong>三娘</strong>：我是个妇人，带着两个孩子，谁会觉得我能翻出什么浪来？</p><p><em>她低头看了看那件缝了大半年的袍子。</em></p><p><strong>三娘</strong>：这件袍子我先不缝了。等你回来再说。</p><p><em>柴绍盯着她。</em></p><p><strong>柴绍</strong>：三娘……你是不是已经想好了？</p><p><em>三娘没回答。微微一笑。</em></p><hr><h4 id="【第-1-集钩子】" tabindex="-1">【第 1 集钩子】 <a class="header-anchor" href="#【第-1-集钩子】" aria-label="Permalink to &quot;【第 1 集钩子】&quot;">​</a></h4><p><em>画面切黑。字幕浮现：</em></p><p><strong>&quot;三娘没有告诉柴绍——这件事，她已经等了很多年。&quot;</strong></p><p><em>切回开场那个穿男装的背影。这次镜头拉远，她身后站着一小队人马。</em></p><hr><p><em>第 1 集 完</em></p><hr><h3 id="第-2-集-月亮与槐花" tabindex="-1">第 2 集：月亮与槐花 <a class="header-anchor" href="#第-2-集-月亮与槐花" aria-label="Permalink to &quot;第 2 集：月亮与槐花&quot;">​</a></h3><blockquote><p>钩子类型：情感冲击 + 闪回预告 时长：约 3 分钟</p></blockquote><hr><h4 id="【开场】" tabindex="-1">【开场】 <a class="header-anchor" href="#【开场】" aria-label="Permalink to &quot;【开场】&quot;">​</a></h4><p><strong>场景：柴府，深夜</strong></p><p><em>柴绍在两个儿子门口站了很久，没进去。怕吵醒。</em></p><p><em>三娘站在走廊另一头，看着他的背影。</em></p><p><strong>三娘（画外音）</strong>：灯光把他的影子拉得很长。我忽然想到——如果他走了，下次见面不知道什么时候。也不知道还能不能见面。</p><p><em>她走过去，把一个包袱塞到他手里。</em></p><p><strong>柴绍</strong>：什么？</p><p><strong>三娘</strong>：干粮。肉脯。还有令武的画。</p><p><em>柴绍打开。一张皱巴巴的纸，炭笔画了四个圈——大的两个小的两个，旁边歪歪扭扭一个&quot;家&quot;字。</em></p><p><em>柴绍的眼眶红了。</em></p><p><strong>柴绍</strong>：三娘。</p><p><strong>三娘</strong>：嗯。</p><p><strong>柴绍</strong>：……我会回来的。</p><p><strong>三娘</strong>：我知道。路上别逞强。遇到巡逻绕着走。你那个脾气，别看到不平事就冲上去——现在不是当侠客的时候。</p><p><em>柴绍笑了。憨，但可靠。</em></p><p><em>他转身出了角门。夜色把他吞进去。脚步声越来越远。</em></p><p><em>三娘站在门口，没关门。夜风吹进来，槐花的气味。远处传来更夫的梆子声，慢悠悠的，一下一下。</em></p><p><em>她站了很久。</em></p><hr><h4 id="【回忆闪回-·-新婚】" tabindex="-1">【回忆闪回 · 新婚】 <a class="header-anchor" href="#【回忆闪回-·-新婚】" aria-label="Permalink to &quot;【回忆闪回 · 新婚】&quot;">​</a></h4><p><em>画面柔化。年轻的柴绍喝醉了酒，拉着三娘的手。</em></p><p><strong>柴绍</strong>（醉）：三娘，你知不知道我第一次见你想什么？</p><p><strong>三娘</strong>（年轻）：想什么？</p><p><strong>柴绍</strong>：我想——这个女人看我的眼神，好像她什么都知道。我有点怕。</p><p><em>三娘等他说下半句。</em></p><p><strong>柴绍</strong>：但后来我想通了——怕就怕吧。反正你什么都知道，那我也不用装了。多省事。</p><p><em>他打了个酒嗝，翻身睡了。</em></p><p><em>三娘盯着他的后脑勺，笑了。</em></p><p><em>闪回结束。</em></p><hr><h4 id="【回到柴府门口】" tabindex="-1">【回到柴府门口】 <a class="header-anchor" href="#【回到柴府门口】" aria-label="Permalink to &quot;【回到柴府门口】&quot;">​</a></h4><p><em>三娘关上门。回到屋里，把旧袍叠好，放进柜子最里面。</em></p><p><em>她的表情在关门的一瞬间变了——从柔软变成坚定，像换了一个人。</em></p><p><strong>三娘</strong>：三宝。</p><p><em>黑暗里传来马三宝带鼻音的声音——他一直没睡，蹲在廊下。</em></p><p><strong>马三宝</strong>：在。</p><p><strong>三娘</strong>：明天一早，把我那套男装找出来。深色的。</p><p><em>两秒沉默。</em></p><p><strong>马三宝</strong>：……夫人？</p><p><strong>三娘</strong>：以后别叫夫人了。叫我李公子。</p><p><em>又是两秒。</em></p><p><strong>马三宝</strong>：那……两位小公子呢？</p><p><strong>三娘</strong>：一起走。告诉哲威，去鄠县外婆家住。</p><p><strong>马三宝</strong>：令武呢？他才三岁，路上——</p><p><strong>三娘</strong>：令武不用告诉。三岁的孩子，你把他扛在肩上他就以为在玩。</p><p><em>马三宝在黑暗中点了点头。</em></p><p><strong>马三宝</strong>：你怕吗？</p><p><em>停顿。</em></p><p><strong>三娘</strong>：怕。</p><p><strong>马三宝</strong>：那还走？</p><p><strong>三娘</strong>：我娘说过一句话——</p><hr><h4 id="【第-2-集钩子】" tabindex="-1">【第 2 集钩子】 <a class="header-anchor" href="#【第-2-集钩子】" aria-label="Permalink to &quot;【第 2 集钩子】&quot;">​</a></h4><p><em>画面突然切到另一个场景——</em></p><p><em>阳光刺眼。一个小女孩从马上摔下来，后脑勺着地。天旋地转。</em></p><p><em>一个女人的脸挡住太阳。</em></p><p><strong>窦氏（画外音）</strong>：怕可以。但不许因为怕就不上马。</p><p><em>黑屏。字幕：</em></p><p><strong>&quot;说完这句话的第二年，她的母亲就死了。&quot;</strong></p><hr><p><em>第 2 集 完</em></p><hr><h3 id="第-3-集-八岁那年的马" tabindex="-1">第 3 集：八岁那年的马 <a class="header-anchor" href="#第-3-集-八岁那年的马" aria-label="Permalink to &quot;第 3 集：八岁那年的马&quot;">​</a></h3><blockquote><p>钩子类型：人物立住 + 揭秘（她不是临时起意） 时长：约 4 分钟</p></blockquote><hr><h4 id="【开场-·-承接上集】" tabindex="-1">【开场 · 承接上集】 <a class="header-anchor" href="#【开场-·-承接上集】" aria-label="Permalink to &quot;【开场 · 承接上集】&quot;">​</a></h4><p><em>画面：阳光灿烂。开皇十八年，长安。</em></p><p><em>八岁的三娘从马上摔下来。不是慢吞吞滑下去——是整个人翻出去，后脑勺先着地。</em></p><p><em>仆妇尖叫。管事刘老三拉长调子喊：三——小——姐——</em></p><p><em>三娘躺在地上看天。长安五月的天蓝得过分。嘴里有土味。</em></p><p><em>母亲的脸挡住太阳。</em></p><p><em>窦氏蹲下来，不扶，不问疼不疼。</em></p><p><strong>窦氏</strong>：摔疼了？</p><p><em>三娘吐出一颗小石子。</em></p><p><strong>三娘</strong>（小）：嗯。</p><p><strong>窦氏</strong>：那记住。马惊了你往后仰，重心全在后面，不摔才怪。下次往前趴，抓鬃毛，夹紧。</p><p><strong>三娘</strong>（小）：那不是趴着了吗？多难看。</p><p><em>窦氏笑了。眼角有细纹，但眼睛亮，像灯芯刚拨过。</em></p><p><strong>窦氏</strong>：难看活着，好看摔死，你选哪个？</p><p><em>三娘想了想，爬起来，拍拍屁股。</em></p><p><strong>三娘</strong>（小）：再骑一次。</p><p><em>窦氏转身走了。走了两步停下来，没回头。</em></p><p><strong>窦氏</strong>：记住——怕可以，但不许因为怕就不上马。</p><hr><h4 id="【快速蒙太奇-母亲的课】" tabindex="-1">【快速蒙太奇：母亲的课】 <a class="header-anchor" href="#【快速蒙太奇-母亲的课】" aria-label="Permalink to &quot;【快速蒙太奇：母亲的课】&quot;">​</a></h4><p><em>画面快速切换，窦氏的声音贯穿：</em></p><p><strong>窦氏（画外）</strong>：你看那个卖炊饼的，寅时出摊，不是因为勤快，是因为寅时的客人不赖账。</p><p><em>（画面：小三娘跟在母亲身后逛街市）</em></p><p><strong>窦氏（画外）</strong>：你二叔输棋就掀桌子——记住，掀桌子的人已经认输了。</p><p><em>（画面：宴席上，一个男人怒掀棋盘。小三娘在角落安静地看）</em></p><p><strong>窦氏（画外）</strong>：你父亲喝了酒就吹牛。你别拆穿他。男人有时候需要觉得自己很厉害，这是他们的炊饼。</p><p><em>（画面：李渊酒后吹嘘，窦氏在旁微笑。小三娘低头偷笑）</em></p><hr><h4 id="【母亲之死】" tabindex="-1">【母亲之死】 <a class="header-anchor" href="#【母亲之死】" aria-label="Permalink to &quot;【母亲之死】&quot;">​</a></h4><p><em>画面转暗。病榻。药味。帷帐后的咳嗽声越来越弱。</em></p><p><em>九岁的三娘贴着门缝偷听。</em></p><p><em>李渊坐在床边，握着窦氏的手。她瘦得不像样，手腕细得像柴禾。</em></p><p><strong>窦氏</strong>（极轻的声音）：……别让他们磨掉了。</p><p><strong>李渊</strong>：磨掉什么？</p><p><em>窦氏没有回答。</em></p><p><strong>三娘（画外音 · 成年）</strong>：我当时不懂。后来才明白——母亲说的&quot;他们&quot;，是这个世道。&quot;别让他们磨掉了&quot;——磨掉的是她身上那股东西。看准了就射的果断，满堂男人面前品评天下的底气。她怕我们被磨成圆的。</p><hr><h4 id="【十一岁-·-被父亲-看见-】" tabindex="-1">【十一岁 · 被父亲&quot;看见&quot;】 <a class="header-anchor" href="#【十一岁-·-被父亲-看见-】" aria-label="Permalink to &quot;【十一岁 · 被父亲&quot;看见&quot;】&quot;">​</a></h4><p><em>宴席。一个老将军在吹嘘以三百骑破千人。</em></p><p><em>三娘安安静静坐在角落，听完了。</em></p><p><em>回家马车上——</em></p><p><strong>三娘</strong>（十一岁）：那位将军说的路线不对。从潼关到华阴走南道，三百骑展不开。要破千人得走北道，绕河滩。</p><p><em>李渊愣了一下，然后笑了。笑容里多了一样东西——像种子冒了芽。</em></p><p><strong>李渊</strong>：你娘教你的？</p><p><strong>三娘</strong>：我自己看的。《六韬》里有。</p><p><em>李渊不再说话。但他的眼神变了。</em></p><p><strong>三娘（画外音）</strong>：从那天起，父亲偶尔会在饭桌上讲一些&quot;不该跟女儿讲&quot;的事——边关、朝堂、将军的得失。我听。不插嘴。但我的眼睛在亮。他看到了。他想起了母亲。</p><hr><h4 id="【揭秘-她一直在准备】" tabindex="-1">【揭秘：她一直在准备】 <a class="header-anchor" href="#【揭秘-她一直在准备】" aria-label="Permalink to &quot;【揭秘：她一直在准备】&quot;">​</a></h4><p><em>画面：婚后。三娘在灯下看地图。</em></p><p><strong>三娘（画外音）</strong>：婚后第二年，我让马三宝去鄠县跑了一趟。</p><p><em>马三宝回来，递上一份东西。</em></p><p><strong>马三宝</strong>：夫人，您要这些干什么？</p><p><strong>三娘</strong>：备着。</p><p><strong>三娘（画外音）</strong>：粮仓存量。周边村落户数。附近山头的亡命之徒。从鄠县到长安的三条路。</p><p><em>三娘把那份东西锁进妆奁底下，压在兵书上面。</em></p><p><strong>三娘（画外音）</strong>：柴绍不知道。他还在猎鹿。</p><p><em>画面：柴绍在猎场上一箭射中奔鹿，兴高采烈。</em></p><p><em>画面：三娘半夜醒来，坐在窗前。月亮很亮，槐树的影子一晃一晃。柴绍在身后打呼。</em></p><p><strong>三娘（画外音）</strong>：我等的东西，我不知道是什么。但我能感觉到。就像马受惊之前会先竖耳朵，风暴来之前空气里有一种闷。我的弓已经拉开了，箭已经搭上了。只是猎物还没出现。</p><p><em>画面叠到第一集柴绍递出竹管的画面——</em></p><p><strong>三娘（画外音）</strong>：直到大业十三年五月十五。</p><hr><h4 id="【第-3-集钩子】" tabindex="-1">【第 3 集钩子】 <a class="header-anchor" href="#【第-3-集钩子】" aria-label="Permalink to &quot;【第 3 集钩子】&quot;">​</a></h4><p><em>画面突切——</em></p><p><em>另一个地方。鄠县县衙。后堂的灯亮着。</em></p><p><em>一个中年男人坐在案后，面前摊着一封加急公文。</em></p><p><em>他的手指在地图上慢慢移动，停在终南山脚——</em></p><p><em>指甲在&quot;李氏庄园&quot;上掐了一道印子。</em></p><p><em>灯光照着他的脸——不年轻了，但眼睛很亮。</em></p><p><em>字幕：</em></p><p><strong>&quot;三娘不知道，有人比她更早看到了那封信。&quot;</strong></p><hr><p><em>第 3 集 完</em></p><hr><h3 id="第-4-集-天亮之前" tabindex="-1">第 4 集：天亮之前 <a class="header-anchor" href="#第-4-集-天亮之前" aria-label="Permalink to &quot;第 4 集：天亮之前&quot;">​</a></h3><blockquote><p>钩子类型：紧张感 + 倒计时 时长：约 3 分钟</p></blockquote><hr><h4 id="【开场】-1" tabindex="-1">【开场】 <a class="header-anchor" href="#【开场】-1" aria-label="Permalink to &quot;【开场】&quot;">​</a></h4><p><em>字幕：五月十八日，寅时。天还黑。</em></p><p><em>三娘穿好男装，照铜镜。镜子里的人像个清瘦少年——但腰上鼓了一块。</em></p><p><em>她低头看了看——是令武的小布老虎。她随手塞进去的，怕路上他闹。</em></p><p><em>她把镜子翻过去，扣在桌上。</em></p><hr><h4 id="【院子里的混乱】" tabindex="-1">【院子里的混乱】 <a class="header-anchor" href="#【院子里的混乱】" aria-label="Permalink to &quot;【院子里的混乱】&quot;">​</a></h4><p><em>马三宝正在跟两个孩子搏斗。</em></p><p><em>柴哲威倒是乖，背着小包袱站着，一脸严肃，像个出征的小将军。</em></p><p><em>柴令武被从被窝里薅出来，半梦半醒且暴怒，骑在马三宝脖子上拽他头发。</em></p><p><strong>柴令武</strong>：要骑马——</p><p><strong>马三宝</strong>：这不是马这是我——哎哟！</p><p><em>三娘走过来，把令武抱下来。小家伙搂住她脖子，脸埋进肩窝。</em></p><p><strong>柴令武</strong>（迷糊）：爹爹呢……</p><p><em>三娘拍拍他的背。令武睡着了。</em></p><p><strong>三娘</strong>：走吧。</p><hr><h4 id="【出城】" tabindex="-1">【出城】 <a class="header-anchor" href="#【出城】" aria-label="Permalink to &quot;【出城】&quot;">​</a></h4><p><em>角门鱼贯而出。七个仆从，两匹马，三个大人，两个小孩。天边没有一丝光。</em></p><p><em>柴哲威走在三娘旁边，仰头看她的男装。</em></p><p><strong>柴哲威</strong>（压低声音）：娘，你穿成这样，不像男人。</p><p><strong>三娘</strong>：哪里不像？</p><p><strong>柴哲威</strong>（认真想了想）：男人不会走路这么好看。</p><p><em>马三宝在后面差点被口水呛到。</em></p><p><em>三娘没理他们，加快脚步。</em></p><hr><h4 id="【路上-·-紧张升级】" tabindex="-1">【路上 · 紧张升级】 <a class="header-anchor" href="#【路上-·-紧张升级】" aria-label="Permalink to &quot;【路上 · 紧张升级】&quot;">​</a></h4><p><em>一行人出了坊门，向南走。天际线有一条极淡的光。</em></p><p><em>忽然——远处传来马蹄声。</em></p><p><em>所有人僵住。</em></p><p><em>马三宝下意识挡到三娘和孩子前面。</em></p><p><em>马蹄声越来越近。</em></p><p><em>三娘把令武抱紧了一些，另一只手按住了腰间——</em></p><p><em>（特写：她的手摸到的不是刀，是那只小布老虎。）</em></p><p><em>几匹马从巷子口闪过。是巡夜的金吾卫，没有往这边看。</em></p><p><em>马蹄声远去。所有人松了一口气。</em></p><p><em>马三宝后背全是汗。</em></p><p><strong>马三宝</strong>（低声）：夫——公子，这也太——</p><p><strong>三娘</strong>（低声）：走。别停。</p><hr><h4 id="【出城门】" tabindex="-1">【出城门】 <a class="header-anchor" href="#【出城门】" aria-label="Permalink to &quot;【出城门】&quot;">​</a></h4><p><em>天快亮了。他们混在出城的商队里，过了南门。</em></p><p><em>柴哲威回头看了一眼长安。</em></p><p><strong>柴哲威</strong>（小声）：娘，我们还回来吗？</p><p><em>三娘没有回答。她也回头看了一眼。</em></p><p><em>长安的城墙在晨光里慢慢变亮。她在这座城里出生、长大、嫁人、生子。</em></p><p><em>她转过头。</em></p><p><strong>三娘</strong>：走。</p><p><em>怀里的柴令武翻了个身，把口水流到了她肩膀上。</em></p><hr><h4 id="【第-4-集钩子】" tabindex="-1">【第 4 集钩子】 <a class="header-anchor" href="#【第-4-集钩子】" aria-label="Permalink to &quot;【第 4 集钩子】&quot;">​</a></h4><p><em>画面切到鄠县——</em></p><p><em>县衙。天刚亮。</em></p><p><em>那个中年人站在院子里，对一个手下说话。</em></p><p><strong>中年人</strong>：去李氏庄园附近，找个地方住下。不要惊动任何人。有人来，有人走，你都给我记下来。</p><p><strong>手下</strong>：大人，您觉得李家的人会来？</p><p><em>中年人看着南边的天际线。</em></p><p><strong>中年人</strong>：不是觉得。是一定会来。</p><p><em>他笑了一下。</em></p><p><strong>中年人</strong>：问题是——来的是谁。</p><p><em>字幕：</em></p><p><strong>&quot;三娘以为自己在布局。但有人的棋，下得更早。&quot;</strong></p><hr><p><em>第 4 集 完</em></p><hr><h3 id="第-5-集-两盘棋" tabindex="-1">第 5 集：两盘棋 <a class="header-anchor" href="#第-5-集-两盘棋" aria-label="Permalink to &quot;第 5 集：两盘棋&quot;">​</a></h3><blockquote><p>钩子类型：双线交汇 + 大悬念 时长：约 4 分钟</p></blockquote><hr><h4 id="【a线-三娘在路上】" tabindex="-1">【A线：三娘在路上】 <a class="header-anchor" href="#【a线-三娘在路上】" aria-label="Permalink to &quot;【A线：三娘在路上】&quot;">​</a></h4><p><em>画面：官道。三娘一行人在走。</em></p><p><em>柴令武终于醒了，骑在马三宝肩上，兴高采烈。</em></p><p><strong>柴令武</strong>：三宝！跑！</p><p><strong>马三宝</strong>（气喘）：小公子……我不是马……</p><p><strong>柴令武</strong>：驾！</p><p><em>柴哲威在旁边走着，时不时回头张望，一副小大人的样子。</em></p><p><em>三娘走在前面，表情平静，但眼睛一直在观察——路上的行人、远处的烟尘、道旁的地形。</em></p><p><strong>三娘（画外音）</strong>：从长安到鄠县，正常走两天。我们带着孩子，得三天。这三天是最危险的——还没到庄园，在路上就是活靶子。</p><p><em>她的目光落在远处一个茶棚上。茶棚前拴着几匹马。</em></p><p><em>三娘停下脚步。</em></p><p><strong>马三宝</strong>：怎么了？</p><p><strong>三娘</strong>（低声）：那几匹马。看蹄铁。</p><p><em>马三宝看了一眼。</em></p><p><strong>马三宝</strong>：……官马。</p><p><strong>三娘</strong>：嗯。官差在里面歇脚。绕路。</p><p><em>一行人拐进旁边的小路。</em></p><hr><h4 id="【b线-鄠县县衙】" tabindex="-1">【B线：鄠县县衙】 <a class="header-anchor" href="#【b线-鄠县县衙】" aria-label="Permalink to &quot;【B线：鄠县县衙】&quot;">​</a></h4><p><em>中年人坐在案后。一个手下进来。</em></p><p><strong>手下</strong>：大人，柴绍已经失踪了。长安那边确认——是夜里走的。</p><p><strong>中年人</strong>：往哪个方向？</p><p><strong>手下</strong>：北。太原方向。</p><p><em>中年人点点头，不意外。</em></p><p><strong>中年人</strong>：柴府呢？还有谁？</p><p><strong>手下</strong>：柴绍的妻子，李渊第三女。两个小孩。还有一些仆从。</p><p><em>中年人端起茶碗，吹了吹。</em></p><p><strong>中年人</strong>：一个女人，两个小孩。</p><p><em>他喝了一口茶。</em></p><p><strong>中年人</strong>：盯着。</p><hr><h4 id="【a线-夜晚露宿】" tabindex="-1">【A线：夜晚露宿】 <a class="header-anchor" href="#【a线-夜晚露宿】" aria-label="Permalink to &quot;【A线：夜晚露宿】&quot;">​</a></h4><p><em>路边，简单的营地。仆从们在轮流守夜。</em></p><p><em>柴哲威和柴令武睡了。</em></p><p><em>三娘坐在树下，没有睡。</em></p><p><em>马三宝凑过来。</em></p><p><strong>马三宝</strong>（低声）：公子，到了鄠县之后……然后呢？</p><p><em>三娘看着远处。月亮又大又亮，和长安柴府窗前看到的是同一个。</em></p><p><strong>三娘</strong>：开仓。</p><p><strong>马三宝</strong>：啊？</p><p><strong>三娘</strong>：李氏庄园的粮仓，存了八年的粮。周围十几个村落，这两年收成不好。有粮，就有人。有人，就有兵。</p><p><em>马三宝张着嘴。</em></p><p><strong>马三宝</strong>：夫——公子，您是什么时候想好的这些？</p><p><em>三娘微微一笑。</em></p><p><strong>三娘</strong>：八年前。</p><p><em>马三宝想起了那次鄠县之行。他终于明白了。</em></p><hr><h4 id="【b线-同一个夜晚】" tabindex="-1">【B线：同一个夜晚】 <a class="header-anchor" href="#【b线-同一个夜晚】" aria-label="Permalink to &quot;【B线：同一个夜晚】&quot;">​</a></h4><p><em>鄠县县衙。</em></p><p><em>中年人也没有睡。他在灯下摊开地图，上面已经密密麻麻标满了记号——李氏庄园的位置、周边村落、山头、水源、道路。</em></p><p><em>他的标记方式——和三娘让马三宝做的调查，重合度极高。</em></p><p><em>一个手下进来。</em></p><p><strong>手下</strong>：大人，李氏庄园那边有动静。管事的好像在清点什么。</p><p><em>中年人放下笔。</em></p><p><strong>中年人</strong>：清点粮仓？</p><p><strong>手下</strong>：像是。</p><p><em>中年人的眼睛亮了。</em></p><p><strong>中年人</strong>：有意思。</p><p><em>他站起来，走到窗前。月亮很亮。</em></p><p><strong>中年人</strong>（自言自语）：李渊，你是让女儿来打前站的？……还是你女儿自己要来的？</p><hr><h4 id="【第-5-集钩子-·-第一季终】" tabindex="-1">【第 5 集钩子 · 第一季终】 <a class="header-anchor" href="#【第-5-集钩子-·-第一季终】" aria-label="Permalink to &quot;【第 5 集钩子 · 第一季终】&quot;">​</a></h4><p><em>画面分屏——</em></p><p><em>左边：三娘在月光下，目光坚定，望向鄠县方向。</em></p><p><em>右边：中年人在灯下，嘴角微扬，望向同一个方向。</em></p><p><em>两个人，两盘棋，即将在同一个棋盘上相遇。</em></p><p><em>字幕渐出：</em></p><p><strong>&quot;她以为鄠县是起点。他以为鄠县是陷阱。&quot;</strong></p><p><strong>&quot;他们都对了。&quot;</strong></p><p><em>黑屏。</em></p><p><strong>第一季完 · 第二季《开仓》即将开始</strong></p><hr><p><em>第 5 集 完</em></p>',412)])])}const d=p(a,[["render",n]]);export{u as __pageData,d as default};
